import React, { useState, useEffect, useCallback } from 'react';
import { transportAPI } from '../services/api';
import api from '../services/api';
import toast from 'react-hot-toast';

const vehicleAPI = {
  getAll:   ()  => api.get('/transport/vehicles'),
  create:   (d) => api.post('/transport/vehicles', d),
};

const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };
const th  = { padding:'10px 14px', textAlign:'left', background:'#F9FAFB', color:'#6B7280', fontSize:10, fontWeight:700, textTransform:'uppercase', borderBottom:'1px solid #E5E7EB', whiteSpace:'nowrap' };
const td  = { padding:'10px 14px', borderBottom:'0.5px solid #F3F4F6', fontSize:12 };

const MOCK_ROUTES = [
  { id:'r1', route_name:'Route A - Gomti Nagar',   route_no:'R01', start_point:'School', end_point:'Gomti Nagar',   distance_km:8,  monthly_fee:1200, enrolled_students:18 },
  { id:'r2', route_name:'Route B - Hazratganj',    route_no:'R02', start_point:'School', end_point:'Hazratganj',    distance_km:5,  monthly_fee:900,  enrolled_students:14 },
  { id:'r3', route_name:'Route C - Aliganj',       route_no:'R03', start_point:'School', end_point:'Aliganj',       distance_km:12, monthly_fee:1500, enrolled_students:22 },
];
const MOCK_VEHICLES = [
  { id:'v1', registration_no:'UP32AB1234', vehicle_type:'school_bus', make_model:'Tata Starbus', capacity:40, route_name:'Route A - Gomti Nagar', driver_name:'Ramesh Kumar', fitness_expiry:'2026-03-01', insurance_expiry:'2026-06-01' },
  { id:'v2', registration_no:'UP32CD5678', vehicle_type:'school_bus', make_model:'Ashok Leyland', capacity:35, route_name:'Route B - Hazratganj', driver_name:'Suresh Singh', fitness_expiry:'2025-12-01', insurance_expiry:'2026-01-01' },
];

export default function Transport() {
  const [tab,         setTab]         = useState('routes');
  const [routes,      setRoutes]      = useState([]);
  const [vehicles,    setVehicles]    = useState([]);
  const [loading,     setLoading]     = useState(true);
  const [isMock,      setIsMock]      = useState(false);
  const [showAddRoute,setShowAddRoute]= useState(false);
  const [showAddVeh,  setShowAddVeh]  = useState(false);
  const [saving,      setSaving]      = useState(false);

  const [routeForm, setRouteForm] = useState({ name:'', no:'', start:'School', end:'', dist:'', fee:'' });
  const [vehForm,   setVehForm]   = useState({ regno:'', type:'school_bus', model:'', capacity:'', routeId:'' });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [rRes, vRes] = await Promise.all([
        transportAPI.getRoutes(),
        vehicleAPI.getAll(),
      ]);
      setRoutes(rRes.data.data || []);
      setVehicles(vRes.data.data || []);
      setIsMock(false);
    } catch {
      setRoutes(MOCK_ROUTES);
      setVehicles(MOCK_VEHICLES);
      setIsMock(true);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const handleAddRoute = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await transportAPI.createRoute({
        routeName:   routeForm.name,
        routeNo:     routeForm.no || undefined,
        startPoint:  routeForm.start || undefined,
        endPoint:    routeForm.end || undefined,
        distanceKm:  parseFloat(routeForm.dist) || undefined,
        monthlyFee:  parseFloat(routeForm.fee) || undefined,
      });
      toast.success('✅ Route saved to database!');
      setShowAddRoute(false);
      setRouteForm({ name:'', no:'', start:'School', end:'', dist:'', fee:'' });
      load();
    } catch (err) {
      toast.error('Failed: ' + (err.response?.data?.message || err.message));
    } finally { setSaving(false); }
  };

  const handleAddVehicle = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await vehicleAPI.create({
        registrationNo: vehForm.regno,
        vehicleType:    vehForm.type,
        makeModel:      vehForm.model || undefined,
        capacity:       parseInt(vehForm.capacity) || undefined,
        routeId:        vehForm.routeId || undefined,
      });
      toast.success('✅ Vehicle saved to database!');
      setShowAddVeh(false);
      setVehForm({ regno:'', type:'school_bus', model:'', capacity:'', routeId:'' });
      load();
    } catch (err) {
      toast.error('Failed: ' + (err.response?.data?.message || err.message));
    } finally { setSaving(false); }
  };

  const today = new Date().toISOString().split('T')[0];
  const totalStudents = routes.reduce((s, r) => s + (parseInt(r.enrolled_students) || 0), 0);

  return (
    <div>
      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Transport Management</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>
            {routes.length} routes · {vehicles.length} vehicles &nbsp;
            {isMock
              ? <span style={{padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700}}>Demo mode</span>
              : <span style={{padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700}}>🟢 Live DB</span>}
          </p>
        </div>
        <div style={{display:'flex',gap:10}}>
          {tab==='routes'   && <button onClick={()=>setShowAddRoute(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ Add Route</button>}
          {tab==='vehicles' && <button onClick={()=>setShowAddVeh(true)}   style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ Add Vehicle</button>}
        </div>
      </div>

      {/* Stats */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:12,marginBottom:16}}>
        {[
          ['Routes',          routes.length,   '#EDE9F8','#1E1B4B'],
          ['Vehicles',        vehicles.length, '#DBEAFE','#1E40AF'],
          ['Students Enrolled',totalStudents,  '#D1FAE5','#065F46'],
          ['Active Vehicles',  vehicles.filter(v=>v.is_active!==false).length, '#FEF3C7','#92400E'],
        ].map(([l,v,bg,c]) => (
          <div key={l} style={{padding:'14px',background:bg,borderRadius:12,textAlign:'center'}}>
            <div style={{fontSize:24,fontWeight:800,color:c,lineHeight:1}}>{v}</div>
            <div style={{fontSize:11,color:c,marginTop:4,fontWeight:600}}>{l}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{display:'flex',gap:0,borderBottom:'2px solid #E5E7EB',marginBottom:0}}>
        {[['routes','🚌 Routes'],['vehicles','🚍 Vehicles']].map(([key,label]) => (
          <button key={key} onClick={()=>setTab(key)}
            style={{padding:'10px 20px',border:'none',borderBottom:tab===key?'2px solid #1E1B4B':'2px solid transparent',background:'transparent',color:tab===key?'#1E1B4B':'#6B7280',fontSize:13,fontWeight:tab===key?700:500,cursor:'pointer',marginBottom:-2}}>
            {label}
          </button>
        ))}
      </div>

      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:'0 0 14px 14px',overflow:'hidden'}}>

        {/* ── ROUTES TAB ── */}
        {tab==='routes' && (
          loading ? <div style={{padding:36,textAlign:'center',color:'#9CA3AF'}}>⏳ Loading…</div> :
          routes.length === 0 ? (
            <div style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
              <div style={{fontSize:40,marginBottom:10}}>🚌</div>
              <div style={{fontWeight:600,color:'#6B7280'}}>No routes yet</div>
              <div style={{fontSize:12,marginTop:4}}>Click "+ Add Route" to create your first transport route</div>
            </div>
          ) : (
            <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
              <thead><tr>
                {['Route No','Route Name','From','To','Distance','Monthly Fee','Students','Status'].map(h=><th key={h} style={th}>{h}</th>)}
              </tr></thead>
              <tbody>
                {routes.map((r,i) => (
                  <tr key={r.id||i} onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'} onMouseLeave={e=>e.currentTarget.style.background=''}>
                    <td style={{...td,fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{r.route_no||'—'}</td>
                    <td style={{...td,fontWeight:700,color:'#111827'}}>{r.route_name}</td>
                    <td style={td}>{r.start_point||'—'}</td>
                    <td style={td}>{r.end_point||'—'}</td>
                    <td style={td}>{r.distance_km ? r.distance_km + ' km' : '—'}</td>
                    <td style={{...td,fontWeight:700}}>₹{Number(r.monthly_fee||0).toLocaleString('en-IN')}</td>
                    <td style={td}>
                      <span style={{padding:'3px 10px',borderRadius:20,fontSize:10,fontWeight:700,background:'#EDE9F8',color:'#1E1B4B'}}>
                        {r.enrolled_students||0} students
                      </span>
                    </td>
                    <td style={td}>
                      <span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:600,background:'#D1FAE5',color:'#065F46'}}>Active</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )
        )}

        {/* ── VEHICLES TAB ── */}
        {tab==='vehicles' && (
          loading ? <div style={{padding:36,textAlign:'center',color:'#9CA3AF'}}>⏳ Loading…</div> :
          vehicles.length === 0 ? (
            <div style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
              <div style={{fontSize:40,marginBottom:10}}>🚍</div>
              <div style={{fontWeight:600,color:'#6B7280'}}>No vehicles yet</div>
              <div style={{fontSize:12,marginTop:4}}>Click "+ Add Vehicle" to register a vehicle</div>
            </div>
          ) : (
            <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
              <thead><tr>
                {['Reg No','Type','Make/Model','Capacity','Route','Driver','Fitness Expiry','Insurance','Status'].map(h=><th key={h} style={th}>{h}</th>)}
              </tr></thead>
              <tbody>
                {vehicles.map((v,i) => {
                  const fitExpired    = v.fitness_expiry   && v.fitness_expiry   < today;
                  const insurExpired  = v.insurance_expiry && v.insurance_expiry < today;
                  return (
                    <tr key={v.id||i} onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'} onMouseLeave={e=>e.currentTarget.style.background=''}>
                      <td style={{...td,fontFamily:'monospace',fontWeight:700,color:'#1E1B4B'}}>{v.registration_no}</td>
                      <td style={td}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#EDE9F8',color:'#1E1B4B',fontWeight:600}}>{v.vehicle_type?.replace('_',' ')}</span></td>
                      <td style={td}>{v.make_model||'—'}</td>
                      <td style={{...td,textAlign:'center'}}>{v.capacity||'—'}</td>
                      <td style={td}>{v.route_name||'—'}</td>
                      <td style={td}>{v.driver_name||'—'}</td>
                      <td style={td}>
                        <span style={{color:fitExpired?'#DC2626':'#065F46',fontWeight:600}}>
                          {fitExpired?'⚠️ ':''}{v.fitness_expiry||'—'}
                        </span>
                      </td>
                      <td style={td}>
                        <span style={{color:insurExpired?'#DC2626':'#065F46',fontWeight:600}}>
                          {insurExpired?'⚠️ ':''}{v.insurance_expiry||'—'}
                        </span>
                      </td>
                      <td style={td}>
                        <span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:600,background:v.is_active!==false?'#D1FAE5':'#FEE2E2',color:v.is_active!==false?'#065F46':'#991B1B'}}>
                          {v.is_active!==false?'Active':'Inactive'}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )
        )}
      </div>

      {/* ── ADD ROUTE MODAL ── */}
      {showAddRoute && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:520,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>🚌 Add Transport Route</div>
              <button onClick={()=>setShowAddRoute(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAddRoute} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Route Name *</label><input required value={routeForm.name} onChange={e=>setRouteForm({...routeForm,name:e.target.value})} placeholder="e.g. Route A - Gomti Nagar" style={inp} autoFocus/></div>
                <div><label style={lbl}>Route No.</label><input value={routeForm.no} onChange={e=>setRouteForm({...routeForm,no:e.target.value})} placeholder="e.g. R01" style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Start Point</label><input value={routeForm.start} onChange={e=>setRouteForm({...routeForm,start:e.target.value})} style={inp}/></div>
                <div><label style={lbl}>End Point</label><input value={routeForm.end} onChange={e=>setRouteForm({...routeForm,end:e.target.value})} placeholder="Area/locality" style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:16}}>
                <div><label style={lbl}>Distance (km)</label><input type="number" step="0.1" value={routeForm.dist} onChange={e=>setRouteForm({...routeForm,dist:e.target.value})} style={inp}/></div>
                <div><label style={lbl}>Monthly Fee (₹)</label><input type="number" value={routeForm.fee} onChange={e=>setRouteForm({...routeForm,fee:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAddRoute(false)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" disabled={saving} style={{padding:'10px 22px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>
                  {saving?'⏳ Saving…':'💾 Save Route'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ── ADD VEHICLE MODAL ── */}
      {showAddVeh && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:520,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>🚍 Add Vehicle</div>
              <button onClick={()=>setShowAddVeh(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAddVehicle} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Registration No. *</label><input required value={vehForm.regno} onChange={e=>setVehForm({...vehForm,regno:e.target.value})} placeholder="e.g. UP32AB1234" style={inp} autoFocus/></div>
                <div><label style={lbl}>Type</label>
                  <select value={vehForm.type} onChange={e=>setVehForm({...vehForm,type:e.target.value})} style={inp}>
                    <option value="school_bus">School Bus</option>
                    <option value="van">Van</option>
                    <option value="auto">Auto</option>
                  </select>
                </div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Make / Model</label><input value={vehForm.model} onChange={e=>setVehForm({...vehForm,model:e.target.value})} placeholder="e.g. Tata Starbus" style={inp}/></div>
                <div><label style={lbl}>Capacity (seats)</label><input type="number" value={vehForm.capacity} onChange={e=>setVehForm({...vehForm,capacity:e.target.value})} placeholder="e.g. 40" style={inp}/></div>
              </div>
              <div style={{marginBottom:16}}>
                <label style={lbl}>Assign Route</label>
                <select value={vehForm.routeId} onChange={e=>setVehForm({...vehForm,routeId:e.target.value})} style={inp}>
                  <option value="">No route assigned</option>
                  {routes.map(r=><option key={r.id} value={r.id}>{r.route_name}</option>)}
                </select>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAddVeh(false)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" disabled={saving} style={{padding:'10px 22px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>
                  {saving?'⏳ Saving…':'💾 Save Vehicle'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
